The `debounce` function is a utility function that limits the rate at which a given function can be called, preventing excessive executions within a short period of time.

```javascript
function debounce(func, wait) {
  let timeout;
  return function(...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(context, args), wait);
  }
}

// Example usage:
const debouncedLog = debounce(console.log, 500);
// Call debouncedLog multiple times in quick succession to see the debouncing in action
debouncedLog('Hello');
debouncedLog('World');
```
